import { Component, EventEmitter, Input, Output } from '@angular/core';

export type RejectReason = 'TYPE' | 'SIZE';

@Component({
    selector: 'app-file-upload',
    templateUrl: './file-upload.component.html',
    styleUrls: ['./file-upload.component.scss'],
})
export class FileUploadComponent {
    @Input() accept = '.csv';
    @Input() maxSizeMB = 50;
    @Input() label = '파일 선택';
    @Output() fileSelected = new EventEmitter<File>();
    @Output() fileRejected = new EventEmitter<{ reason: RejectReason; message: string }>();

    onChange(event: Event): void {
        const input = event.target as HTMLInputElement;
        const file = input.files?.[0];
        if (!file) return;
        this.handleFile(file);
        input.value = '';
    }

    handleFile(file: File): void {
        const lower = file.name.toLowerCase();
        const accepted = this.accept
            .split(',')
            .map((s) => s.trim().toLowerCase())
            .some((ext) => lower.endsWith(ext));
        if (!accepted) {
            this.fileRejected.emit({
                reason: 'TYPE',
                message: `허용되지 않는 파일 형식입니다 (${this.accept}만 허용).`,
            });
            return;
        }
        const maxBytes = this.maxSizeMB * 1024 * 1024;
        if (file.size > maxBytes) {
            this.fileRejected.emit({
                reason: 'SIZE',
                message: `파일 크기가 ${this.maxSizeMB}MB를 초과합니다.`,
            });
            return;
        }
        this.fileSelected.emit(file);
    }
}

