import { SelectionModel } from '@angular/cdk/collections';
import { Component, EventEmitter, Input, Output, TrackByFunction } from '@angular/core';
import { PageEvent } from '@angular/material/paginator';
import { Sort } from '@angular/material/sort';
import { PageResponse } from '../../../core/models/page-response.model';
import { ColumnDef } from './column-def.model';

@Component({
    selector: 'app-data-grid',
    templateUrl: './data-grid.component.html',
    styleUrls: ['./data-grid.component.scss'],
})
export class DataGridComponent<T> {
    @Input() columns: ColumnDef[] = [];
    @Input() pageData: PageResponse<T> | null = null;
    @Input() pageSizeOptions: number[] = [10, 20, 50, 100];
    @Input() selectable = false;
    @Input() trackBy: TrackByFunction<T> = (_, item) => (item as { id?: unknown }).id as never;

    @Output() pageChange = new EventEmitter<{ page: number; size: number }>();
    @Output() sortChange = new EventEmitter<{ active: string; direction: 'asc' | 'desc' | '' }>();
    @Output() selectionChange = new EventEmitter<T[]>();
    @Output() rowClick = new EventEmitter<T>();

    readonly selection = new SelectionModel<T>(true, []);

    get displayedColumns(): string[] {
        const base = this.columns.map((c) => c.key);
        return this.selectable ? ['__select', ...base] : base;
    }

    onPage(e: PageEvent): void {
        this.pageChange.emit({ page: e.pageIndex + 1, size: e.pageSize });
    }

    onSort(e: Sort): void {
        this.sortChange.emit({ active: e.active, direction: e.direction as 'asc' | 'desc' | '' });
    }

    onRowClick(row: T): void {
        this.rowClick.emit(row);
    }

    toggleRow(row: T): void {
        this.selection.toggle(row);
        this.selectionChange.emit(this.selection.selected);
    }

    isSelected(row: T): boolean {
        return this.selection.isSelected(row);
    }

    isAllSelected(): boolean {
        const rows = this.pageData?.items ?? [];
        return rows.length > 0 && rows.every((r) => this.selection.isSelected(r));
    }

    toggleAll(): void {
        const rows = this.pageData?.items ?? [];
        if (this.isAllSelected()) {
            rows.forEach((r) => this.selection.deselect(r));
        } else {
            rows.forEach((r) => this.selection.select(r));
        }
        this.selectionChange.emit(this.selection.selected);
    }
}

