import com.devwogns.trmdict.common.response.PageResponse;
import com.devwogns.trmdict.module.domain.dto.DomainSearchDto;
import com.devwogns.trmdict.module.domain.mapper.DomainMapper;
import com.devwogns.trmdict.module.domain.vo.DomainDtlVo;
import com.devwogns.trmdict.module.domain.vo.DomainListVo;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;

import java.util.Arrays;
import java.util.HashSet;
import java.util.List;
import java.util.Set;

@Slf4j
@Service
@RequiredArgsConstructor
public class DomainService {

    private static final Set<String> SORTABLE_COLUMNS = new HashSet<>(Arrays.asList(
            "std_dmn_nm",
            "std_dmn_clsf_nm",
            "std_dmn_group_nm",
            "data_type_nm",
            "mdfcn_dt",
            "reg_dt"
    ));

    private static final Set<String> SORTABLE_DIRS = new HashSet<>(Arrays.asList("asc", "desc"));

    private static final String DEFAULT_SORT_BY = "mdfcn_dt";
    private static final String DEFAULT_SORT_DIR = "desc";

    private static final int DEFAULT_PAGE = 1;
    private static final int DEFAULT_SIZE = 20;
    private static final int MAX_SIZE = 100;

    private final DomainMapper mapper;

    public PageResponse<DomainListVo> search(DomainSearchDto criteria) {
        normalizeAndValidate(criteria);

        long total = mapper.countSearch(criteria);
        List<DomainListVo> items = mapper.search(criteria);

        return PageResponse.of(items, criteria.getPage(), criteria.getSize(), total);
    }

    public DomainDtlVo findById(Long id) {
        DomainDtlVo dtl = mapper.findById(id);
        if (dtl == null) {
            throw new BusinessException(ErrorCode.DOMAIN_2001);
        }
        return dtl;
    }

    private void normalizeAndValidate(DomainSearchDto criteria) {
        if (criteria.getPage() == null || criteria.getPage() < 1) {
            criteria.setPage(DEFAULT_PAGE);
        }
        if (criteria.getSize() == null || criteria.getSize() < 1) {
            criteria.setSize(DEFAULT_SIZE);
        }
        if (criteria.getSize() > MAX_SIZE) {
            throw new BusinessException(ErrorCode.COMMON_0001);
        }

        if (criteria.getSortBy() == null || criteria.getSortBy().isEmpty()) {
            criteria.setSortBy(DEFAULT_SORT_BY);
        } else if (!SORTABLE_COLUMNS.contains(criteria.getSortBy().toLowerCase())) {
            throw new BusinessException(ErrorCode.COMMON_0001);
        } else {
            criteria.setSortBy(criteria.getSortBy().toLowerCase());
        }

        if (criteria.getSortDir() == null || criteria.getSortDir().isEmpty()) {
            criteria.setSortDir(DEFAULT_SORT_DIR);
        } else if (!SORTABLE_DIRS.contains(criteria.getSortDir().toLowerCase())) {
            throw new BusinessException(ErrorCode.COMMON_0001);
        } else {
            criteria.setSortDir(criteria.getSortDir().toLowerCase());
        }
    }
}

