package com.devwogns.trmdict.common.paging;

import lombok.AccessLevel;
import lombok.AllArgsConstructor;
import lombok.Getter;

import java.util.Set;

@Getter
@AllArgsConstructor(access = AccessLevel.PRIVATE)
public class PageRequest {

    private final int page;          // 1-based
    private final int size;
    private final String sortColumn; // 클라이언트 입력 (정규화 안 됨)
    private final String sortDirection;

    public static PageRequest of(int page, int size, String sortColumn, String sortDirection) {
        int safePage = Math.max(1, page);
        int safeSize = Math.max(1, size);
